"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[8308],{31296(r,n,e){e.r(n),e.d(n,{assets:()=>p,contentTitle:()=>i,default:()=>u,frontMatter:()=>a,metadata:()=>t,toc:()=>c});const t=JSON.parse('{"id":"cpp20/spaceship-operator","title":"\u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator \u27fa)","description":"C++20 \u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator \u27fa) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp20/05-spaceship-operator.md","sourceDirName":"cpp20","slug":"/cpp20/05-spaceship-operator","permalink":"/LearnModernCpp/docs/cpp20/05-spaceship-operator","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp20","permalink":"/LearnModernCpp/docs/tags/cpp-20"},{"inline":true,"label":"spaceship_operator","permalink":"/LearnModernCpp/docs/tags/spaceship-operator"}],"version":"current","sidebarPosition":6,"frontMatter":{"sidebar_position":6,"slug":"05-spaceship-operator","title":"\u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator \u27fa)","description":"C++20 \u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator \u27fa) \u6559\u5b66\u793a\u4f8b","tags":["cpp20","spaceship_operator"]},"sidebar":"docs","previous":{"title":"\u7b80\u5199\u51fd\u6570\u6a21\u677f (Abbreviated Function Templates)","permalink":"/LearnModernCpp/docs/cpp20/04-abbreviated-templates"},"next":{"title":"\u6307\u5b9a\u521d\u59cb\u5316\u5668 (Designated Initializers)","permalink":"/LearnModernCpp/docs/cpp20/06-designated-initializers"}}');var s=e(74848),o=e(28453);const a={sidebar_position:6,slug:"05-spaceship-operator",title:"\u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator \u27fa)",description:"C++20 \u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator \u27fa) \u6559\u5b66\u793a\u4f8b",tags:["cpp20","spaceship_operator"]},i="\u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator <=>)",p={},c=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function d(r){const n={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,o.R)(),...r.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.header,{children:(0,s.jsxs)(n.h1,{id:"\u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26-spaceship-operator-",children:["\u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator ",(0,s.jsx)(n.code,{children:"<=>"}),")"]})}),"\n",(0,s.jsxs)(n.p,{children:["C++20 \u6807\u51c6\u5f15\u5165\u7684 \u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator ",(0,s.jsx)(n.code,{children:"<=>"}),") \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"]}),"\n",(0,s.jsx)(n.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,s.jsx)(n.pre,{children:(0,s.jsx)(n.code,{className:"language-cpp",metastring:'title="cpp20/05_spaceship_operator.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator <=>)\r\n * \u6240\u5c5e\u6807\u51c6: C++20\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: <=> \u8fd0\u7b97\u7b26\uff08\u53c8\u79f0\u592a\u7a7a\u8239\u8fd0\u7b97\u7b26\uff09\u53ef\u4ee5\u4e00\u6b21\u6027\u6bd4\u8f83\u4e24\u4e2a\u5bf9\u8c61\uff0c\r\n *          \u8fd4\u56de\u4e09\u79cd\u7ed3\u679c\u4e4b\u4e00\uff1a\u5c0f\u4e8e\u3001\u7b49\u4e8e\u3001\u5927\u4e8e\u3002\u7f16\u8bd1\u5668\u53ef\u4ee5\u636e\u6b64\r\n *          \u81ea\u52a8\u751f\u6210\u5168\u90e8\u516d\u4e2a\u6bd4\u8f83\u8fd0\u7b97\u7b26\uff08<, >, <=, >=, ==, !=\uff09\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++17 \u53ca\u4e4b\u524d\uff0c\u4e3a\u4e00\u4e2a\u7c7b\u578b\u5b9e\u73b0\u5b8c\u6574\u7684\u6bd4\u8f83\u8fd0\u7b97\u7b26\r\n *             \u9700\u8981\u624b\u51996\u4e2a\u91cd\u8f7d\uff0c\u4ee3\u7801\u5197\u4f59\u4e14\u5bb9\u6613\u51fa\u9519\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - <=> \u8fd4\u56de strong_ordering\u3001weak_ordering \u6216 partial_ordering\r\n *   - = default \u53ef\u4ee5\u81ea\u52a8\u751f\u6210\u6309\u6210\u5458\u6bd4\u8f83\u7684 <=>\r\n *   - \u7f16\u8bd1\u5668\u53ef\u4ee5\u4ece <=> \u81ea\u52a8\u63a8\u5bfc\u51fa <, >, <=, >=\r\n *   - == \u548c != \u9700\u8981\u5355\u72ec\u9ed8\u8ba4\u6216\u81ea\u5b9a\u4e49\uff08C++20 \u89c4\u5219\uff09\r\n * ============================================================\r\n */\r\n\r\n#include <compare>\r\n#include <iostream>\r\n#include <string>\r\n#include <vector>\r\n#include <set>\r\n#include <algorithm>\r\n\r\n// ===================== basic_usage() =====================\r\n\r\n// \u6700\u7b80\u5355\u7684\u7528\u6cd5\uff1a\u4f7f\u7528 =default \u81ea\u52a8\u751f\u6210\u6240\u6709\u6bd4\u8f83\u8fd0\u7b97\u7b26\r\nstruct Point {\r\n    int x;\r\n    int y;\r\n\r\n    // \u9ed8\u8ba4 <=> \u6309\u6210\u5458\u987a\u5e8f\u9010\u4e00\u6bd4\u8f83\uff08\u5148\u6bd4\u8f83 x\uff0c\u82e5\u76f8\u7b49\u518d\u6bd4\u8f83 y\uff09\r\n    auto operator<=>(const Point&) const = default;\r\n    // \u6ce8\u610f\uff1a= default \u7684 <=> \u540c\u65f6\u751f\u6210 == \u548c !=\r\n};\r\n\r\nvoid basic_usage() {\r\n    std::cout << "--- \u57fa\u7840\u7528\u6cd5 ---\\n\\n";\r\n\r\n    Point p1{1, 2}, p2{1, 3}, p3{1, 2};\r\n\r\n    // \u81ea\u52a8\u751f\u6210\u7684\u516d\u4e2a\u6bd4\u8f83\u8fd0\u7b97\u7b26\r\n    std::cout << "p1{1,2} vs p2{1,3}:\\n";\r\n    std::cout << "  p1 == p2: " << std::boolalpha << (p1 == p2) << "\\n";\r\n    std::cout << "  p1 != p2: " << (p1 != p2) << "\\n";\r\n    std::cout << "  p1 <  p2: " << (p1 < p2)  << "\\n";\r\n    std::cout << "  p1 >  p2: " << (p1 > p2)  << "\\n";\r\n    std::cout << "  p1 <= p2: " << (p1 <= p2) << "\\n";\r\n    std::cout << "  p1 >= p2: " << (p1 >= p2) << "\\n";\r\n\r\n    std::cout << "\\np1{1,2} vs p3{1,2}:\\n";\r\n    std::cout << "  p1 == p3: " << (p1 == p3) << "\\n";\r\n\r\n    // \u76f4\u63a5\u4f7f\u7528 <=> \u8fd0\u7b97\u7b26\r\n    auto result = p1 <=> p2;\r\n    if (result < 0) std::cout << "\\np1 < p2 (\u901a\u8fc7 <=> \u5224\u65ad)\\n";\r\n    else if (result > 0) std::cout << "\\np1 > p2 (\u901a\u8fc7 <=> \u5224\u65ad)\\n";\r\n    else std::cout << "\\np1 == p2 (\u901a\u8fc7 <=> \u5224\u65ad)\\n";\r\n\r\n    // \u53ef\u4ee5\u7528\u5728\u6392\u5e8f\u4e2d\r\n    std::vector<Point> points = {{3, 1}, {1, 2}, {2, 0}, {1, 1}};\r\n    std::sort(points.begin(), points.end());\r\n    std::cout << "\\n\u6392\u5e8f\u540e\u7684\u70b9: ";\r\n    for (const auto& p : points) {\r\n        std::cout << "(" << p.x << "," << p.y << ") ";\r\n    }\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ===================== advanced_usage() =====================\r\n\r\n// strong_ordering\uff1a\u5b8c\u5168\u6709\u5e8f\uff0c\u533a\u5206\u6bcf\u4e2a\u4e0d\u540c\u7684\u503c\r\n// \u4f8b\u5982\uff1a\u6574\u6570\u7684\u6bd4\u8f83\r\nstruct StudentID {\r\n    int id;\r\n\r\n    std::strong_ordering operator<=>(const StudentID& other) const {\r\n        return id <=> other.id;\r\n    }\r\n    bool operator==(const StudentID& other) const = default;\r\n};\r\n\r\n// weak_ordering\uff1a\u5f31\u5e8f\uff0c\u67d0\u4e9b\u4e0d\u540c\u7684\u503c\u53ef\u80fd\u88ab\u89c6\u4e3a\u7b49\u4ef7\r\n// \u4f8b\u5982\uff1a\u4e0d\u533a\u5206\u5927\u5c0f\u5199\u7684\u5b57\u7b26\u4e32\u6bd4\u8f83\r\nstruct CaseInsensitiveString {\r\n    std::string value;\r\n\r\n    std::weak_ordering operator<=>(const CaseInsensitiveString& other) const {\r\n        // \u9010\u5b57\u7b26\u6bd4\u8f83\uff08\u5ffd\u7565\u5927\u5c0f\u5199\uff09\r\n        auto to_lower = [](char c) -> char {\r\n            return (c >= \'A\' && c <= \'Z\') ? static_cast<char>(c + 32) : c;\r\n        };\r\n        size_t len = std::min(value.size(), other.value.size());\r\n        for (size_t i = 0; i < len; ++i) {\r\n            char a = to_lower(value[i]);\r\n            char b = to_lower(other.value[i]);\r\n            if (a < b) return std::weak_ordering::less;\r\n            if (a > b) return std::weak_ordering::greater;\r\n        }\r\n        if (value.size() < other.value.size()) return std::weak_ordering::less;\r\n        if (value.size() > other.value.size()) return std::weak_ordering::greater;\r\n        return std::weak_ordering::equivalent;\r\n    }\r\n\r\n    bool operator==(const CaseInsensitiveString& other) const {\r\n        return (*this <=> other) == 0;\r\n    }\r\n};\r\n\r\n// partial_ordering\uff1a\u504f\u5e8f\uff0c\u67d0\u4e9b\u503c\u53ef\u80fd\u4e0d\u53ef\u6bd4\u8f83\r\n// \u4f8b\u5982\uff1a\u6d6e\u70b9\u6570\uff08NaN \u4e0e\u4efb\u4f55\u503c\u90fd\u4e0d\u53ef\u6bd4\u8f83\uff09\r\nstruct Temperature {\r\n    double celsius;\r\n\r\n    std::partial_ordering operator<=>(const Temperature& other) const {\r\n        return celsius <=> other.celsius;  // double \u7684 <=> \u8fd4\u56de partial_ordering\r\n    }\r\n    bool operator==(const Temperature& other) const {\r\n        return celsius == other.celsius;\r\n    }\r\n};\r\n\r\n// \u81ea\u5b9a\u4e49 <=>\uff1a\u6df7\u5408\u4e0d\u540c\u7c7b\u578b\u6210\u5458\r\nstruct Employee {\r\n    std::string department;  // \u5148\u6309\u90e8\u95e8\u6392\u5e8f\r\n    int level;               // \u518d\u6309\u7ea7\u522b\u6392\u5e8f\r\n    std::string name;        // \u6700\u540e\u6309\u540d\u5b57\u6392\u5e8f\r\n\r\n    auto operator<=>(const Employee&) const = default;\r\n    // \u9ed8\u8ba4\u6309\u58f0\u660e\u987a\u5e8f\u9010\u6210\u5458\u6bd4\u8f83\r\n};\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- \u9ad8\u7ea7\u7528\u6cd5 ---\\n\\n";\r\n\r\n    // strong_ordering \u6f14\u793a\r\n    std::cout << "-- strong_ordering (\u5b8c\u5168\u6709\u5e8f) --\\n";\r\n    StudentID s1{1001}, s2{1002}, s3{1001};\r\n    auto sr = s1 <=> s2;\r\n    std::cout << "\u5b66\u53f7 1001 vs 1002: "\r\n              << (sr < 0 ? "\u5c0f\u4e8e" : sr > 0 ? "\u5927\u4e8e" : "\u7b49\u4e8e") << "\\n";\r\n    std::cout << "\u5b66\u53f7 1001 vs 1001: "\r\n              << ((s1 <=> s3) == std::strong_ordering::equal ? "\u76f8\u7b49" : "\u4e0d\u76f8\u7b49") << "\\n";\r\n\r\n    // weak_ordering \u6f14\u793a\r\n    std::cout << "\\n-- weak_ordering (\u5f31\u5e8f/\u7b49\u4ef7) --\\n";\r\n    CaseInsensitiveString a{"Hello"}, b{"hello"}, c{"World"};\r\n    std::cout << "\\"Hello\\" vs \\"hello\\": "\r\n              << ((a <=> b) == std::weak_ordering::equivalent ? "\u7b49\u4ef7" : "\u4e0d\u7b49\u4ef7") << "\\n";\r\n    std::cout << "\\"Hello\\" < \\"World\\": "\r\n              << ((a <=> c) < 0 ? "\u662f" : "\u5426") << "\\n";\r\n\r\n    // partial_ordering \u6f14\u793a\r\n    std::cout << "\\n-- partial_ordering (\u504f\u5e8f) --\\n";\r\n    Temperature t1{36.5}, t2{37.0};\r\n    Temperature t_nan{std::numeric_limits<double>::quiet_NaN()};\r\n\r\n    std::cout << "36.5\xb0C vs 37.0\xb0C: "\r\n              << ((t1 <=> t2) < 0 ? "\u5c0f\u4e8e" : "\u4e0d\u5c0f\u4e8e") << "\\n";\r\n\r\n    auto nan_result = t1 <=> t_nan;\r\n    if (nan_result == std::partial_ordering::unordered) {\r\n        std::cout << "36.5\xb0C vs NaN: \u4e0d\u53ef\u6bd4\u8f83 (unordered)\\n";\r\n    }\r\n\r\n    // \u5728\u5bb9\u5668\u4e2d\u4f7f\u7528\r\n    std::cout << "\\n-- \u5728\u6709\u5e8f\u5bb9\u5668\u4e2d\u4f7f\u7528 --\\n";\r\n    std::set<Point> point_set = {{1, 2}, {3, 4}, {1, 1}, {2, 2}};\r\n    std::cout << "set \u4e2d\u7684\u70b9\uff08\u81ea\u52a8\u6709\u5e8f\uff09: ";\r\n    for (const auto& p : point_set) {\r\n        std::cout << "(" << p.x << "," << p.y << ") ";\r\n    }\r\n    std::cout << "\\n";\r\n}\r\n\r\n// ===================== pitfalls() =====================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- \u6613\u9519\u70b9 ---\\n\\n";\r\n\r\n    // \u9677\u96311\uff1a= default \u7684 <=> \u53ef\u4ee5\u81ea\u52a8\u751f\u6210 ==\uff0c\u4f46\u81ea\u5b9a\u4e49\u7684\u4e0d\u884c\r\n    std::cout << "1. \u81ea\u5b9a\u4e49 <=> \u4e0d\u4f1a\u81ea\u52a8\u751f\u6210 == \u548c !=\\n";\r\n    std::cout << "   \u5982\u679c\u81ea\u5b9a\u4e49\u4e86 operator<=>\uff0c\u9700\u8981\u989d\u5916\u58f0\u660e operator==\\n";\r\n    std::cout << "   \u901a\u5e38: bool operator==(const T&) const = default;\\n\\n";\r\n\r\n    // \u9677\u96312\uff1aordering \u7c7b\u578b\u7684\u5c42\u7ea7\u5173\u7cfb\r\n    std::cout << "2. ordering \u7c7b\u578b\u7684\u9690\u5f0f\u8f6c\u6362:\\n";\r\n    std::cout << "   strong_ordering \u2192 weak_ordering \u2192 partial_ordering\\n";\r\n    std::cout << "   \u53cd\u5411\u8f6c\u6362\u4e0d\u5141\u8bb8\uff08\u4e0d\u80fd\u4ece\u5f31\u5e8f\u5f97\u5230\u5f3a\u5e8f\uff09\\n\\n";\r\n\r\n    // \u9677\u96313\uff1a\u6210\u5458\u4e2d\u6709\u6307\u9488\u65f6 = default \u53ef\u80fd\u4e0d\u7b26\u5408\u9884\u671f\r\n    std::cout << "3. \u5982\u679c\u6210\u5458\u4e2d\u6709\u6307\u9488\uff0c= default \u6bd4\u8f83\u7684\u662f\u6307\u9488\u5730\u5740\uff0c\u4e0d\u662f\u6307\u5411\u7684\u5185\u5bb9\\n";\r\n    std::cout << "   \u8fd9\u79cd\u60c5\u51b5\u9700\u8981\u81ea\u5b9a\u4e49 <=> \u6765\u6bd4\u8f83\u6307\u5411\u7684\u503c\\n\\n";\r\n\r\n    // \u9677\u96314\uff1a\u6d6e\u70b9\u6570\u6210\u5458\u4f1a\u5bfc\u81f4 partial_ordering\r\n    std::cout << "4. \u5982\u679c\u7c7b\u6210\u5458\u4e2d\u5305\u542b double/float\uff0c\\n";\r\n    std::cout << "   = default \u7684 <=> \u8fd4\u56de partial_ordering\uff08\u56e0\u4e3a NaN \u4e0d\u53ef\u6bd4\u8f83\uff09\\n";\r\n\r\n    struct HasDouble {\r\n        int id;\r\n        double score;\r\n        auto operator<=>(const HasDouble&) const = default;\r\n    };\r\n\r\n    // \u9a8c\u8bc1\uff1a\u8fd4\u56de\u7c7b\u578b\u662f partial_ordering\r\n    using result_type = decltype(HasDouble{} <=> HasDouble{});\r\n    std::cout << "   HasDouble \u7684 <=> \u662f partial_ordering: "\r\n              << std::boolalpha\r\n              << std::is_same_v<result_type, std::partial_ordering> << "\\n\\n";\r\n\r\n    // \u9677\u96315\uff1a\u6bd4\u8f83\u987a\u5e8f\r\n    std::cout << "5. = default \u7684 <=> \u6309\u6210\u5458\u58f0\u660e\u987a\u5e8f\u6bd4\u8f83\\n";\r\n    std::cout << "   \u5982\u679c\u60f3\u6309\u4e0d\u540c\u987a\u5e8f\uff0c\u5fc5\u987b\u81ea\u5b9a\u4e49 <=>\\n";\r\n}\r\n\r\n// ===================== main() =====================\r\nint main() {\r\n    std::cout << "===== \u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 <=> - C++20 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,s.jsx)(n.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsx)(n.li,{children:(0,s.jsxs)(n.a,{href:"https://en.cppreference.com/w/cpp/language/default_comparisons",children:["cppreference: \u4e09\u8def\u6bd4\u8f83\u8fd0\u7b97\u7b26 (Spaceship Operator ",(0,s.jsx)(n.code,{children:"<=>"}),")"]})}),"\n"]})]})}function u(r={}){const{wrapper:n}={...(0,o.R)(),...r.components};return n?(0,s.jsx)(n,{...r,children:(0,s.jsx)(d,{...r})}):d(r)}},28453(r,n,e){e.d(n,{R:()=>a,x:()=>i});var t=e(96540);const s={},o=t.createContext(s);function a(r){const n=t.useContext(o);return t.useMemo(function(){return"function"==typeof r?r(n):{...n,...r}},[n,r])}function i(r){let n;return n=r.disableParentContext?"function"==typeof r.components?r.components(s):r.components||s:a(r.components),t.createElement(o.Provider,{value:n},r.children)}}}]);